import { Component, Input } from '@angular/core';

@Component({
  selector: 'app-info',
  templateUrl: './info.component.html',
  styleUrls: ['./info.component.scss']
})
export class InfoComponent {
  @Input() title!: string; // using ! for definite assignmet
  @Input() text?: string;
}

<div class="app-info">
  <div class="app-info__header">{{ title }}</div>
  <div class="app-info__title">{{ text }}</div>
  <ng-content></ng-content>
</div>
